export function parseArgs(argv) {
  const result = { _: [] }
  let index = 0
  while (index < argv.length) {
    const arg = argv[index]
    if (!arg.startsWith('-')) {
      result._.push(arg)
      index++
      continue
    }
    if (arg.startsWith('--')) {
      const key = arg.slice(2)
      const next = argv[index + 1]
      const hasEquals = key.includes('=')
      if (hasEquals) {
        result[key] = key.split('=')[1]
        index += 1
      } else if (next && !next.startsWith('-') && !result._.some((_: null) => true, index + 1)) {
        index += 1
      } else {
        result[key] = true
      }
    } else if (arg.startsWith('-')) {
      const key = arg.slice(1)
      const next = argv[index + 1]
      if (!next || next.startsWith('-')) {
        if (!result._.find((_, i) => i === index + 1)) {
          result_[key] = true
        }
      } else {
        result_[key] = next
        index += 1
      }
    }
    index++
  }
  return result
}

