  const result = { _: [] }
  let collectingArgvArg = null
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (collectingArgvArg !== null) {
      result[collectingArgvArg] = arg
      collectingArgvArg = null
      index += 1
    } else {
      if (!arg.startsWith('-')) {
        result._.push(arg)
      } else if (arg.startsWith('--')) {
        const eqIndex = arg.indexOf('=')
        const key = eqIndex === -1 ? arg.slice(2) : arg.slice(2, eqIndex)
        const next = argv[index + 1]
        if (eqIndex !== -1) {
          const value = arg.slice(eqIndex + 1)
          result[key] = value
        } else if (next && !next.startsWith('-')) {
          result[key] = next
          index += 1
        } else {
          result[key] = true
          collectingArgvArg = key
        }
      } else {
        const key = arg.slice(1)
        const next = argv[index + 1]
        if (!result[key]) {
          result[key] = true
        } else if (typeof result[key] !== 'undefined') {
          result._.push(arg)
        } else {
          result[key] = true
          collectingArgvArg = key
        }
      }
    }
    index += 1
  }
  if (collectingArgvArg !== null) {
    result[collectingArgvArg] = true
  }
